mapper.select:
SELECT c.*, cc.name as category_name, u.real_name as publisher_name,
       (SELECT COUNT(*) FROM registration r WHERE r.competition_id = c.id) as current_participants
FROM competition c
LEFT JOIN competition_category cc ON c.category_id = cc.id
LEFT JOIN user u ON c.publisher_id = u.id

    
        AND c.title LIKE CONCAT('%', #{title}, '%')
    
    
        AND c.category_id = #{categoryId}
    
    
        AND c.competition_type = #{competitionType}
    
    
        AND c.status = #{status}
    
    
        AND c.publisher_id = #{publisherId}
    

ORDER BY c.create_time DESC

mapper.update:
UPDATE competition
title = #{title}, description = #{description}, category_id = #{categoryId}, competition_type = #{competitionType}, start_time = #{startTime}, end_time = #{endTime}, registration_start_time = #{registrationStartTime}, registration_end_time = #{registrationEndTime}, max_participants = #{maxParticipants}, fee = #{fee}, location = #{location}, status = #{status}, need_work = #{needWork}, need_scoring = #{needScoring},
WHERE id = #{id}
